const GlobalStyles = createGlobalStyle`
    .modal-video {
        width: 100%;
        height: calc(100vh - 55px);
    }

    .modal-fullscreen .modal-content {
        background-color: black;
        border: none;
    }

    .modal-header .btn-close {
        filter: invert(1); /* white close button */
    }
`;


const StyledCom = styled.div`
    .banner-holder {
        // min-height: 400px;
        min-height: 250px;
        max-height: 100%;
        height: 100%;
        position: relative;
        display: flex;
        align-items: center;
        justify-content: center;

        .image-holder {
            min-height: 400px;
            max-height: 100%;
            height: 100%;
            position: absolute;
            top: 0;
            left: 0;

        }

        .content-data {
            position: relative;
            z-index: 1;
            text-align: center;
            padding-top: 100px;

            h1 {
                font-size: 48px;
                margin-top: 20px;
                position: relative;
                font-weight: 800;
                text-align: center;
                color: white;
				// text-shadow: 0px 0px 10px rgba(0, 0, 0, 1);
            }

            h1::after {
                content: "";
                position: absolute;
                height: calc(100% + 10px);
                width: calc(100% + 40px);
                background: var(--primary-color);
                bottom: -5px;
                left: 50%;
                transform: translateX(-50%);
                z-index: -1;
				border-radius: 10px;
            }

            .sub-title {
                background: var(--primary-color);
                color: #ffffff;
                font-size: 18px;
                letter-spacing: 2px;
                padding: 2px 10px;
                font-weight: 700;
                margin-bottom: 20px;
            }

            @media (max-width: 1024px) {
                h1 {
                    font-size: 32px;
                }
            }

            @media (max-width: 768px) {
                min-height: 250px;

                .image-holder {
                    min-height: 250px;
                }
            }
        }
    }

    .testimonial-section {
        padding: 60px 0;

        .video-grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
            gap: 30px;
        }

        .video-thumbnail {
            position: relative;
            cursor: pointer;
			border-radius: 10px;
			overflow: hidden;
			height: 200px;


            img {
                width: 100%;
				height: 100%;
                object-fit: cover;
				object-position: bottom
            }

            .play-button {
                position: absolute;
                top: 50%;
                left: 50%;
                transform: translate(-50%, -50%);
                background: white;
                border-radius: 50px;
                height: 60px;
                display: flex;
                align-items: center;
                justify-content: center;
				color: black;
				padding: 5px 10px;
            }

            .play-button svg {
                fill: var(--secondary-color-dark);
                width: 40px;
                height: 40px;
            }
        }
		.review-video-holder  {
			grid-column: 1 / -1;

			.video-thumbnail{
				height: 500px;
			}
		}
    }



`;

