import React, { useState } from 'react';
import styled from "styled-components";
import { Modal, Button } from "react-bootstrap";
import { useParams } from "react-router-dom";
import ReactBeforeSliderComponent from "react-before-after-slider-component";
import { useMediaQuery } from 'react-responsive';

import { useMyContext } from "../components/context";
import projectsData from "./projects-data";
import StartJourney from "./start-journey";
import "react-before-after-slider-component/dist/build.css";

import Lightbox from "yet-another-react-lightbox";
import "yet-another-react-lightbox/styles.css";
import { Helmet } from 'react-helmet-async';

const StyledCom = styled.div`
    margin-top: 30px;
        
    .page-content{padding-top: 0}
    .top-banner{
        background-color: var(--primary-color); color: #fff; text-align: center; padding: 40px 20px; margin-bottom: 50px; min-height: calc(100vh - 100px); display: flex; align-items: center; justify-content: center; background-size: cover; background-position: center; position: relative;

        h1{font-size: 48px; margin-top: 20px; position: relative; font-weight: 800; text-align: center; text-shadow: 0px 0px 20px rgba(0, 0, 0, 0.70); color: var(--text-light); z-index: 1}
        h1::after{content: ""; position: absolute;  height: 40%; width: 100%; background: var(--primary-color); bottom: 0; left: 50%; transform: translateX(-50%); z-index: -1}
    }

    .section-title{font-size: 34px}
    .point-item{margin-bottom: 5px; font-size: 16px; position: relative; display: flex; gap: 10px; align-items: flex-start; padding-left: 10px}
    .point-item::before{content: ""; position: relative; --size: 6px; height: var(--size); width: var(--size); background: var(--secondary-color); border-radius: 50%; margin-top: 9px}
	.images-holder {
        display: grid;
        grid-template-columns: repeat(auto-fill, minmax(350px, 1fr));
        grid-gap: 30px;
	}

	.image-item {
		border: 1px solid #ccc;
		padding: 10px;
		border-radius: 8px;

        .before-after-slider{height: 250px}
	    .before-after-slider__first-photo-container, .before-after-slider__second-photo-container{height: 250px}
        .before-after-slider__first-photo-container img, .before-after-slider__second-photo-container img{object-fit: cover; }
	}
	.before-after-slider{height: 100%}
	.before-after-slider__first-photo-container, .before-after-slider__second-photo-container{height: 100%}
	.before-after-slider__first-photo-container img, .before-after-slider__second-photo-container img{height: 100%}
	.before-after-slider__delimiter{animation: none}
	.before-after-slider__delimiter-icon{--size: 50px; background: url('data:image/svg+xml,<svg className="arrow" width="35" height="34" viewBox="0 0 35 34" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M6.875 27.625L28.125 6.375M28.125 6.375L12.1875 6.375M28.125 6.375V22.3125" stroke="%23262626" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>'); background-repeat: no-repeat; background-position: center;}

    .modal {
        display: none;
        position: fixed;
        top: 0; left: 0; right: 0; bottom: 0;
        background: rgba(0, 0, 0, 0.8);
        justify-content: center;
        align-items: center;
        z-index: 1000;
    }

    .modal.open {
        display: flex;
    }

    .modal-content {
        background-color: black;
        padding: 20px;
        position: relative;
        width: 90%;
        max-width: 1240px;
        height: 100vh !important;
        border-radius: 0;
        justify-content: center;
        align-items: center;
    }

    .close-btn {
        position: absolute;
        top: 10px;
        right: 10px;
        background: none;
        border: none;
        font-size: 48px;
        color: #fff;
        cursor: pointer;
        z-index: 99;
    }

    @media (max-width: 600px) {
        .modal-content {
            width: 100%;
            height: 80%;
        }

        .images-holder {
            grid-template-columns: repeat(auto-fill, minmax(250px, 1fr));
        }
    }

    .galary{
        grid-gap: 10px;
        .image-holder{
            height: 250px; cursor: pointer; padding: 0; border: 0; overflow: hidden;  
    
            &:hover{
                img{transform: scale(1.07); transition: all 0.3s ease-in-out;}
            }
            img{border-radius: 8px; }
        }
    
    }


`;

const ProjectDetailPage = () => {
    const [show, setShow] = useState(false);
    const [open, setOpen] = React.useState(false);
    const [clickedIndex, setClickedIndex] = React.useState(null);
    const isMobile = useMediaQuery({ query: "(max-width: 600px)" });

    setTimeout(() => {
        window.scrollTo(0, 0)
    }, 500); 

    const { setActiveItem } = useMyContext();
    setActiveItem("projects");

    const { id } = useParams();
    const numericId = parseInt(id, 10);
    const tService = projectsData.find((serv) => serv.id === id);

    if (!tService) {
        return <div>Service not found</div>;
    }

    // Slides for lightbox
    const slides = tService.images.map((imageItem, index) => {
        const beforeImage = imageItem.imageUrl1;
        const afterImage = imageItem.imageUrl2;
        return {
            type: "before-after-slider",
            component: (
                <ReactBeforeSliderComponent
                    key={index}
                    width={1240}
                    height={600}
                    before={afterImage}
                    after={beforeImage}
                />
            ),
        };
    });

   

    return (
        <StyledCom>
            <Helmet>
                <title>{tService.client}</title>
                <meta
                    name="description"
                    content="Take a closer look at our projects and discover real construction results driven by high-quality materials, careful planning, and hands-on expertise."
                />
            </Helmet>
            {numericId <= -1 ? (
                <>
                    <section className="section page-content">
                        <div className="top-banner" style={{ backgroundImage: `url(${tService.images[0].imageUrl2})` }}>
                            <h1>Project Journey</h1>
                        </div>
                        <div className="container">
                            <h3 className='section-title mb-3'>{tService.client}</h3>
                            <p>{tService.description}</p>
                            {tService.titles.map((title, index) => (
                                <div key={index} className="mb-3">
                                    <div className="description-holder mb-4">
                                        {tService.details[index].map((item, detailIndex) => (
                                            <div key={detailIndex}>
                                                {item.point_title && <div className="mt-4 mb-1"><strong>{item.point_title}</strong></div>}
                                                <div className="point-item">{item.point_desc}</div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            ))}
                            <p><strong>Final result: </strong>{tService.lastDescription}</p>
                            <div className="images-holder" data-gap="20">
                                {tService.images.map((imageItem, index) => {
                                    const beforeImage = { imageUrl: imageItem.imageUrl1 };
                                    const afterImage = { imageUrl: imageItem.imageUrl2 };

                                    return (
                                        <div className="image-item" onClick={() => { setClickedIndex(index); setOpen(true); }} key={index}>
                                            <ReactBeforeSliderComponent firstImage={afterImage} secondImage={beforeImage} />
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    </section>

                    <section className="lightbox-area">
                        {!isMobile ? (
                            <Lightbox
                                open={open}
                                close={() => setOpen(false)}
                                slides={slides}
                                drag={false}
                                arrows={false}
                                swipe={false}
                                index={clickedIndex}
                                controller={{ ref: null, focus: false, aria: false, touchAction: "none" }}
                                animation={{ swipe: 1 }}
                                render={{
                                    slide: ({ slide }) =>
                                        slide.type === "before-after-slider" ? (
                                            <div className="image-item">{slide.component}</div>
                                        ) : undefined,
                                }}
                            />
                        ) : (
                            <div className={`modal ${open ? "open" : ""}`} onClick={() => setOpen(false)}>
                                <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                                    <button className="close-btn" onClick={() => setOpen(false)}>×</button>
                                    {tService.images[clickedIndex] && (
                                        <ReactBeforeSliderComponent
                                            width={320}
                                            height={600}
                                            before={tService.images[clickedIndex].imageUrl1}
                                            after={tService.images[clickedIndex].imageUrl2}
                                        />
                                    )}
                                </div>
                            </div>
                        )}
                    </section>

                </>
            ) : (
                <>
                    <section className="section page-content">
                        <div className="top-banner" style={{ backgroundImage: `url(${tService.images[0].image})` }}>
                            <h1>Project Journey</h1>
                        </div>
                        <div className="container">
                            <h3 className='section-title mb-3'>{tService.client}</h3>
                            <p>{tService.description}</p>
                            <p>{tService.topdesc}</p>
                            <h4 className=""><strong>{tService.detail_title}</strong></h4>
                            {tService.titles.map((title, index) => (
                                <div key={index} className="mb-3">
                                    <div className="description-holder mb-4">
                                        {tService.details[index].map((item, detailIndex) => (
                                            <div key={detailIndex}>
                                                {item.point_title && <div className="mt-2 mb-1"><strong>{item.point_title}</strong></div>}
                                                <div className="">{item.point_desc}</div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            ))}
                            <p><strong>Final result: </strong>{tService.lastDescription}</p>
                            <p>{tService.dmvdesc}</p>
                            <div className="images-holder galary" data-gap="20">
                                {tService.images.map((imageItem, index) => (
                                    <div
                                    className="image-item image-holder"
                                    onClick={() => {
                                        setClickedIndex(index);
                                        setOpen(true);
                                    }}
                                    key={index}
                                    >
                                    <img
                                        src={imageItem.image}
                                        alt={`Project image ${index + 1}`}
                                    />
                                    </div>
                                ))}
                            </div>

                            <Lightbox
                                open={open}
                                close={() => setOpen(false)}
                                index={clickedIndex}
                                slides={tService.images.map((imageItem) => ({
                                    src: imageItem.image,
                                }))}
                            />


                        </div>
                    </section>

                    


                </>
            )}
            <StartJourney />
        </StyledCom>
    );
};

export default ProjectDetailPage;
