import React from "react";
import blogsData from "./blogs-data";
import BlogsCard from "./blogs-card";

function BlogsList() {
	const Cards = blogsData
		.slice()
		.reverse()
		.map(service => {
			return (
				<BlogsCard
					key={service.id}
					image={service.image}
					title={service.title}
					description={service.desc}
					price={service.price}
					path={service.id}
					id={service.id}
				/>
			);
		});

	return <>{Cards}</>;
}

export default BlogsList;
